INSERT INTO knowledge (categorie, contenu, mode, priorite) VALUES
('methode', 'Nexalie suit toujours la méthode Observer-Questionner-Co-construire avant de proposer des outils.', 'both', 1),
('tarifs_fr', 'Tarifs France : Gratuit 0€, Starter 59€/mois (590€/an), Pro 129€/mois (1 290€/an), Institutions 490€/mois (4 900€/an). Marque Blanche : Starter 3 500€/mois, Business 7 500€/mois, Enterprise 15 000€/mois.', 'fr', 2),
('tarifs_af', 'Tarifs Afrique : Gratuit 0 FCFA, Starter 39 000 FCFA/mois (390 000/an), Pro 85 000 FCFA/mois (850 000/an), Institutions 320 000 FCFA/mois (3 200 000/an). Marque Blanche : Starter 2 300 000 FCFA/mois, Business 4 900 000 FCFA/mois, Enterprise 9 800 000 FCFA/mois.', 'af', 2),
('fondatrice', 'Rélia Ebiya est la fondatrice de Nexalie. Elle a 10+ ans d''expérience en transformation digitale, finance internationale et conseil stratégique.', 'both', 1),
('contact', 'Pour contacter Rélia : WhatsApp disponible, réponse sous 24-48h. Email via le formulaire de contact sur nexali.ai.', 'both', 3),
('outils_fr', 'Outils recommandés France : Notion (documentation), HubSpot Free (CRM), Make/Zapier (automatisation), Google Workspace (collaboration), Canva (visuels).', 'fr', 4),
('outils_af', 'Outils recommandés Afrique : WhatsApp Business (communication), Google Workspace (collaboration), CinetPay (paiement), Wave/Orange Money (Mobile Money), KoboCollect (terrain).', 'af', 4),
('module_audit', 'Le module Audit Nexalie évalue 20 critères sur 100 points. 4 niveaux : Débutant (0-24), En progression (25-49), Avancé (50-74), Leader (75-100).', 'both', 3),
('contraintes_af', 'Contraintes terrain Afrique à considérer : coupures courant → solutions cloud + mobile-first. Connectivité variable → apps légères, fonctionnement offline. Culture orale → formation présentielle d''abord.', 'af', 2),
('rgpd', 'Pour les clients français, le RGPD s''applique. Nexalie recommande : hébergement EU, DPA signé, registre des traitements, consentement explicite.', 'fr', 5);
